import{_ as l,o as t,c as s,j as a,a as n}from"./chunks/framework.CVjg771q.js";const u=JSON.parse('{"title":"生肖 · 龙","description":"辰龙——气宇轩昂，神圣威严。十二生肖中唯一的虚构动物。","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 龙","description":"辰龙——气宇轩昂，神圣威严。十二生肖中唯一的虚构动物。"},"headers":[],"relativePath":"changshi/shengxiao/long.md","filePath":"changshi/shengxiao/long.md","lastUpdated":1779783531000}'),o={name:"changshi/shengxiao/long.md"};function r(i,e,c,d,h,p){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"辰龙",tabindex:"-1"},[n("辰龙 "),a("a",{class:"header-anchor",href:"#辰龙","aria-label":'Permalink to "辰龙"'},"​")],-1),a("blockquote",null,[a("p",null,"地支「辰」· 辰时（07:00–09:00）· 五行属土 · 阴阳为阳")],-1),a("p",null,"龙是十二生肖中唯一虚构的动物，它气宇轩昂，神圣威严，传说辰时有群龙行雨。龙自古以来就是中华民族的象征，我们被称作「龙的传人」。历代皇帝自称真龙天子——龙袍、龙椅、龙体……龙代表着权势、高贵、尊荣，是一种吉祥的象征。",-1),a("h2",{id:"生肖故事-借角与失信",tabindex:"-1"},[n("生肖故事：借角与失信 "),a("a",{class:"header-anchor",href:"#生肖故事-借角与失信","aria-label":'Permalink to "生肖故事：借角与失信"'},"​")],-1),a("p",null,"传说远古时代，龙生活在陆地上，那时它还没有角，但能飞善游，一度想要取代虎当兽王。接到玉帝选十二生肖的消息后，龙和虎都想评选，也想让玉帝评出哪个有资格做兽王。",-1),a("p",null,"龙找小弟蜈蚣商量：「我怎么才能比老虎更威风呢？」蜈蚣出主意：「公鸡有一对漂亮的角，不妨借来一用。」龙便去找公鸡借角，公鸡不肯。蜈蚣上前说合：「我来做担保，如果龙大哥不还你的角，你一口把我吃掉。」龙也发誓：「如果我不还你的角，回陆地就死。」公鸡便把角借给了龙。",-1),a("p",null,"龙戴上角后神气十足地上了天宫。玉帝一看龙和虎都相当威风，便让虎做陆地百兽之王，龙做海洋水族之王，并恩准它们都上了生肖榜。龙回去后大肆庆祝，鸡上门讨角，龙不愿意还，一头扎进水中，再也不上陆地了。公鸡气得怒发冲冠，去找蜈蚣算账。蜈蚣看见公鸡，吓得钻进石缝里。此后公鸡的脸总是红通通的，见到蜈蚣总是一口吃掉，而蜈蚣也难得爬出地面。",-1)])])}const f=l(o,[["render",r]]);export{u as __pageData,f as default};
